SELECT n1.n_name AS supp_nation, n2.n_name AS cust_nation, EXTRACT(YEAR FROM o_orderdate) AS l_year, SUM(l_extendedprice * (1 - l_discount)) AS volume FROM supplier, lineitem, orders, customer, nation n1, nation n2 WHERE s_suppkey = l_suppkey AND o_orderkey = l_orderkey AND c_custkey = o_custkey AND s_nationkey = n1.n_nationkey AND c_nationkey = n2.n_nationkey AND n1.n_name = 'GERMANY' AND n2.n_name = 'FRANCE' GROUP BY n1.n_name, n2.n_name, EXTRACT(YEAR FROM o_orderdate) ORDER BY n1.n_name, n2.n_name, l_year;